import XCTest

/// E2E tests that launch the real app with real media generated by ffmpeg.
///
/// These tests exercise the full pipeline: CLI subprocess invocation,
/// JSON envelope parsing, and results display. They require ffmpeg on
/// the system PATH and are selected by the `UITests-E2E` test plan.
///
/// **Note:** On macOS 26 (Tahoe) beta, the SwiftUI `Window` scene may
/// not expose its window in the XCUITest accessibility hierarchy. Tests
/// guard against this with `waitForMainWindow()` and `XCTSkipUnless`.
@MainActor
final class RealScanTests: XCTestCase {
    let app = XCUIApplication()
    var mediaDir: URL?

    override func setUpWithError() throws {
        continueAfterFailure = false
        do {
            mediaDir = try TestMedia.createVideoDirectory()
        } catch TestMedia.TestMediaError.ffmpegNotFound {
            throw XCTSkip("ffmpeg not found — skipping E2E video tests")
        }
    }

    override func tearDownWithError() throws {
        if let dir = mediaDir {
            TestMedia.cleanup(dir)
        }
    }

    // MARK: - Video Scan

    func testVideoScan_findsNearDuplicate() throws {
        guard let dir = mediaDir else { throw XCTSkip("No media directory") }

        // Launch with the real CLI (no mock) but seed the directory
        app.launchEnvironment["DD_UI_TEST_SCAN_DIR"] = dir.path
        app.launch()

        try XCTSkipUnless(
            app.waitForMainWindow(),
            "macOS 26: Window scene not in accessibility hierarchy"
        )

        // The setup screen shows a "Start Scan" button.
        let startScanButton = app.buttons["Start Scan"]
        XCTAssertTrue(
            app.waitForElement(startScanButton, timeout: 10),
            "Start Scan button should appear after dependency check"
        )

        // Start scan — the real CLI runs against the generated videos.
        startScanButton.click()

        // Wait for results (real scan may take up to 30s).
        let newScanButton = app.buttons["New Scan"]
        XCTAssertTrue(
            app.waitForElement(newScanButton, timeout: 60),
            "Results should appear after scanning real media"
        )

        // video_a and video_b are near-duplicates — at least one pair expected.
        let keepA = app.buttons["Keep A"]
        XCTAssertTrue(
            app.waitForElement(keepA, timeout: 5),
            "Keep A button should be visible (at least one pair found)"
        )
    }

    // MARK: - Image Scan

    func testImageScan_findsNearDuplicate() throws {
        guard let dir = mediaDir else { throw XCTSkip("No media directory") }

        // Generate images in the same directory
        try createTestImages(in: dir)

        app.launchEnvironment["DD_UI_TEST_SCAN_DIR"] = dir.path
        app.launchEnvironment["DD_UI_TEST_MODE"] = "image"
        app.launch()

        try XCTSkipUnless(
            app.waitForMainWindow(),
            "macOS 26: Window scene not in accessibility hierarchy"
        )

        let startScanButton = app.buttons["Start Scan"]
        XCTAssertTrue(
            app.waitForElement(startScanButton, timeout: 10),
            "Start Scan button should appear"
        )

        startScanButton.click()

        // Wait for results.
        let newScanButton = app.buttons["New Scan"]
        XCTAssertTrue(
            app.waitForElement(newScanButton, timeout: 60),
            "Results should appear after scanning images"
        )
    }

    // MARK: - Content Mode

    func testContentMode_completesWithoutError() throws {
        guard let dir = mediaDir else { throw XCTSkip("No media directory") }

        app.launchEnvironment["DD_UI_TEST_SCAN_DIR"] = dir.path
        app.launchEnvironment["DD_UI_TEST_CONTENT"] = "1"
        app.launch()

        try XCTSkipUnless(
            app.waitForMainWindow(),
            "macOS 26: Window scene not in accessibility hierarchy"
        )

        let startScanButton = app.buttons["Start Scan"]
        XCTAssertTrue(
            app.waitForElement(startScanButton, timeout: 10),
            "Start Scan button should appear"
        )

        startScanButton.click()

        // Content hashing adds time. Wait longer.
        let newScanButton = app.buttons["New Scan"]
        XCTAssertTrue(
            app.waitForElement(newScanButton, timeout: 90),
            "Results should appear after content-mode scan"
        )
    }

    // MARK: - Helpers

    private func createTestImages(in dir: URL) throws {
        // Create simple BMP images: 2 near-identical + 1 different.
        // BMP header: 14-byte file header + 40-byte DIB header, 24-bit RGB.
        let width: Int32 = 64
        let height: Int32 = 64
        let rowSize = Int((3 * width + 3) / 4) * 4  // Padded to 4 bytes
        let pixelDataSize = rowSize * Int(height)
        let fileSize: Int32 = 54 + Int32(pixelDataSize)

        func writeBMP(to url: URL, red: UInt8, green: UInt8, blue: UInt8) throws {
            var data = Data()
            // BMP file header (14 bytes)
            data.append(contentsOf: [0x42, 0x4D])  // "BM"
            withUnsafeBytes(of: fileSize.littleEndian) { data.append(contentsOf: $0) }
            data.append(contentsOf: [0, 0, 0, 0])  // Reserved
            withUnsafeBytes(of: Int32(54).littleEndian) { data.append(contentsOf: $0) }
            // DIB header (40 bytes)
            withUnsafeBytes(of: Int32(40).littleEndian) { data.append(contentsOf: $0) }
            withUnsafeBytes(of: width.littleEndian) { data.append(contentsOf: $0) }
            withUnsafeBytes(of: height.littleEndian) { data.append(contentsOf: $0) }
            withUnsafeBytes(of: Int16(1).littleEndian) { data.append(contentsOf: $0) }  // Planes
            withUnsafeBytes(of: Int16(24).littleEndian) { data.append(contentsOf: $0) }  // Bits per pixel
            data.append(contentsOf: [UInt8](repeating: 0, count: 24))  // Remaining DIB header
            // Pixel data
            for _ in 0..<Int(height) {
                for _ in 0..<Int(width) {
                    data.append(contentsOf: [blue, green, red])  // BGR format
                }
                // Row padding
                let padding = rowSize - Int(width) * 3
                if padding > 0 {
                    data.append(contentsOf: [UInt8](repeating: 0, count: padding))
                }
            }
            try data.write(to: url)
        }

        // image_a.bmp and image_b.bmp: nearly identical (differ by 1 channel value)
        try writeBMP(to: dir.appendingPathComponent("image_a.bmp"), red: 200, green: 100, blue: 50)
        try writeBMP(to: dir.appendingPathComponent("image_b.bmp"), red: 201, green: 100, blue: 50)
        // image_c.bmp: different
        try writeBMP(to: dir.appendingPathComponent("image_c.bmp"), red: 0, green: 255, blue: 0)
    }
}
